// In an ADX database, Azure Monitor workspace, or Sentinel table,
// the table name changes but the pipe idea stays the same.
SigninLogs
| where TimeGenerated > ago(24h)
| summarize Attempts = count() by ResultType
| top 5 by Attempts desc

// Run by a database admin. Replace the app id and tenant.
.add database Samples viewers ('aadapp=00000000-0000-0000-0000-000000000000;contoso.com') 'Foundry Kusto MCP read access'

.show database Samples principals

